 1	import { Card } from '@patternfly/react-core';
 2	import _ from 'lodash';
 3	import * as React from 'react';
 4	import { Record } from '../../api/ipfix';
 5	import { Stats } from '../../api/loki';
 6	import { RecordType } from '../../model/flow-query';
 7	import { Warning } from '../../model/warnings';
 8	import { TimeRange } from '../../utils/datetime';
 9	import { FlowsQuerySummaryContent } from './flows-query-summary-content';
10	import './query-summary.css';
11	
12	export interface FlowQuerySummaryProps {
13	  flows: Record[];
14	  stats?: Stats;
15	  type: RecordType;
16	  range: number | TimeRange;
17	  loading?: boolean;
18	  lastRefresh?: Date;
19	  lastDuration?: number;
20	  warning?: Warning;
21	  isShowQuerySummary?: boolean;
22	  toggleQuerySummary?: () => void;
23	}
24	
25	export const FlowsQuerySummary: React.FC<FlowQuerySummaryProps> = ({
26	  flows,
27	  stats,
28	  type,
29	  range,
30	  loading,
31	  lastRefresh,
32	  lastDuration,
33	  warning,
34	  isShowQuerySummary,
35	  toggleQuerySummary
36	}) => {
37	  if (!_.isEmpty(flows) && stats) {
38	    return (
39	      <Card id="query-summary">
40	        <FlowsQuerySummaryContent
41	          className="summary-container"
42	          direction="row"
43	          flows={flows}
44	          type={type}
45	          numQueries={stats.numQueries}
46	          limitReached={stats.limitReached}
47	          range={range}
48	          loading={loading}
49	          lastRefresh={lastRefresh}
50	          lastDuration={lastDuration}
51	          warning={warning}
52	          isShowQuerySummary={isShowQuerySummary}
53	          toggleQuerySummary={toggleQuerySummary}
54	        />
55	      </Card>
56	    );
57	  }
58	  return <></>;
59	};
60	
61	export default FlowsQuerySummary;

