 1	import { render, waitFor } from '@testing-library/react';
 2	import userEvent from '@testing-library/user-event';
 3	import * as React from 'react';
 4	
 5	import { MetricType, RecordType } from '../../../model/flow-query';
 6	import { FlowsSample, getTestFlows } from '../../__tests-data__/flows';
 7	import { FlowsQuerySummary } from '../flows-query-summary';
 8	
 9	describe('<FlowsQuerySummary />', () => {
10	  const now = new Date();
11	
12	  const mocks = {
13	    isShowQuerySummary: false,
14	    toggleQuerySummary: jest.fn(),
15	    flows: FlowsSample,
16	    type: 'flowLog' as RecordType,
17	    metricType: 'Bytes' as MetricType,
18	    stats: {
19	      limitReached: false,
20	      numQueries: 1,
21	      dataSources: ['loki']
22	    },
23	    range: 300,
24	    lastRefresh: now
25	  };
26	
27	  it('should render component', async () => {
28	    const { container } = render(<FlowsQuerySummary {...mocks} />);
29	    await waitFor(() => {
30	      expect(container.querySelector('#query-summary-content')).toBeTruthy();
31	    });
32	  });
33	
34	  it('should show summary', async () => {
35	    const { container } = render(<FlowsQuerySummary {...mocks} />);
36	    await waitFor(() => {
37	      expect(container.querySelector('#flowsCount')).toBeTruthy();
38	    });
39	
40	    expect(container.querySelector('#flowsCount')?.textContent).toBe('3 Flows');
41	    expect(container.querySelector('#bytesCount')?.textContent).toBe('161 kB');
42	    expect(container.querySelector('#packetsCount')?.textContent).toBe('1k Packets');
43	    expect(container.querySelector('#bytesPerSecondsCount')?.textContent).toBe('538 Bps');
44	    expect(container.querySelector('#lastRefresh')?.textContent).toBe(now.toLocaleTimeString());
45	  });
46	
47	  it('should format summary', async () => {
48	    const { container } = render(
49	      <FlowsQuerySummary
50	        {...mocks}
51	        flows={getTestFlows(1005)}
52	        stats={{ limitReached: true, numQueries: 1, dataSources: ['loki'] }}
53	      />
54	    );
55	    await waitFor(() => {
56	      expect(container.querySelector('#flowsCount')).toBeTruthy();
57	    });
58	
59	    expect(container.querySelector('#flowsCount')?.textContent).toBe('1k+ Flows');
60	    expect(container.querySelector('#bytesCount')?.textContent).toBe('757+ MB');
61	    expect(container.querySelector('#packetsCount')?.textContent).toBe('1k+ Packets');
62	    expect(container.querySelector('#bytesPerSecondsCount')?.textContent).toBe('2.52+ MBps');
63	    expect(container.querySelector('#lastRefresh')?.textContent).toBe(now.toLocaleTimeString());
64	  });
65	
66	  it('should toggle panel', async () => {
67	    const user = userEvent.setup();
68	    const { container } = render(<FlowsQuerySummary {...mocks} />);
69	    await waitFor(() => {
70	      expect(container.querySelector('#query-summary-toggle')).toBeTruthy();
71	    });
72	
73	    await user.click(container.querySelector('#query-summary-toggle')!);
74	    expect(mocks.toggleQuerySummary).toHaveBeenCalledTimes(1);
75	  });
76	});

